// TestCheckRedirect_StripsCustomHeadersCrossHost verifies that Config.Headers
// (custom credential headers like X-API-Key) are dropped on cross-host 3xx
// hops, alongside Authorization. Go's net/http only strips a fixed allowlist
// of standard auth headers (Authorization, Cookie) on cross-host redirects;
// without explicit stripping, user-configured credential headers would be
// forwarded verbatim to the third-party redirect target.
func TestCheckRedirect_StripsCustomHeadersCrossHost(t *testing.T) {
	t.Parallel()

	// downstream captures whatever headers arrive after the cross-host hop.
	var downstreamHeaders http.Header
	downstream := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		downstreamHeaders = r.Header.Clone()
		w.WriteHeader(http.StatusOK)
	}))
	defer downstream.Close()

	// upstream issues a 302 to downstream (different host:port from upstream).
	upstream := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		http.Redirect(w, r, downstream.URL+"/", http.StatusFound)
	}))
	defer upstream.Close()

	cfg := &config.Config{
		BaseURL: upstream.URL,
		Headers: map[string]string{
			"X-API-Key":     "secret-api-key-value",
			"X-Auth-Token":  "secret-token-value",
			"X-Trace-Id":    "trace-123", // non-credential; also stripped because we can't tell which is which
		},
	}
	c := New(cfg, 5*time.Second, 0)

	req, err := http.NewRequest("GET", upstream.URL+"/start", nil)
	if err != nil {
		t.Fatalf("NewRequest: %v", err)
	}
	req.Header.Set("Authorization", "Bearer should-be-stripped")
	for k, v := range cfg.Headers {
		req.Header.Set(k, v)
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		t.Fatalf("Do: %v", err)
	}
	resp.Body.Close()

	if downstreamHeaders == nil {
		t.Fatalf("downstream did not receive the redirected request")
	}

	for _, h := range []string{"Authorization", "X-API-Key", "X-Auth-Token", "X-Trace-Id"} {
		if got := downstreamHeaders.Get(h); got != "" {
			t.Errorf("cross-host hop leaked %s = %q to third-party host", h, got)
		}
	}
}

// TestCheckRedirect_PreservesCustomHeadersSameHost confirms the strip is
// scoped to cross-host hops: same-host 3xx (a common pagination or auth-flow
// shape) must keep the Config.Headers intact so subsequent calls don't
// silently lose API-key auth on every redirect.
func TestCheckRedirect_PreservesCustomHeadersSameHost(t *testing.T) {
	t.Parallel()

	var (
		seenAtFinal http.Header
		hop         int
	)
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		hop++
		if hop == 1 {
			// Relative redirect — same host.
			http.Redirect(w, r, "/final", http.StatusFound)
			return
		}
		seenAtFinal = r.Header.Clone()
		w.WriteHeader(http.StatusOK)
	}))
	defer srv.Close()

	cfg := &config.Config{
		BaseURL: srv.URL,
		Headers: map[string]string{"X-API-Key": "same-host-keep"},
	}
	c := New(cfg, 5*time.Second, 0)

	req, _ := http.NewRequest("GET", srv.URL+"/start", nil)
	for k, v := range cfg.Headers {
		req.Header.Set(k, v)
	}

	resp, err := c.HTTPClient.Do(req)
	if err != nil {
		t.Fatalf("Do: %v", err)
	}
	resp.Body.Close()

	if got := seenAtFinal.Get("X-API-Key"); got != "same-host-keep" {
		t.Errorf("same-host hop dropped X-API-Key; got %q, want same-host-keep", got)
	}
	if !strings.HasSuffix(strings.TrimRight(srv.URL, "/"), srv.URL[len("http://"):]) {
		// Sanity: same-host case really used a same-host redirect target.
		t.Fatalf("test wiring broken: redirect should have been same-host")
	}
}
